+impl fmt::Debug for NitroSketch {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        f.debug_struct("NitroSketch")
+            .field("precision", &self.precision)
+            .field("register_count", &self.registers.len())
+            .finish_non_exhaustive()
+    }
