+    let span = tracing::span!(
+        target: "fsqlite.trace_export",
+        tracing::Level::DEBUG,
+        "trace_export",
+        spans_exported,
+        export_latency_us
+    );
+    let _guard = span.enter();
+    tracing::debug!("trace export observed");
+}
+
